class Solution {
public:
    int maxVowels(string s, int k) {
        int maxVowels = 0;
        for (int i = 0; i <= s.length() - k; i++) {
            int vowelCount = 0;
            for (int j = i; j < i + k; j++) {
                if (s[j] == 'a' || s[j] == 'e' || s[j] == 'i' || s[j] == 'o' || s[j] == 'u') {
                    vowelCount++;
                }
            }
            maxVowels = max(maxVowels, vowelCount);
        }
        return maxVowels;
    }
};
